const req = items[0].json;
const input = req.body || {};

return [
  {
    json: {
      caseId: input.testCaseId ?? "Unknown Test Case",
      status: input.status ?? "UNKNOWN",
      message: input.message ?? "",
      teststeps: input.executed_steps
        .map((step, index) => `${index + 1}. ${step}`)
        .join('\n') ?? "",
      screenshot: input.screenshot_base64 ?? "",
      timestamp: input.timestamp ?? new Date().toISOString(),
      url: input.url ?? "",

      steps: input.message 
        ? input.message.match(/Step \d+:.+/g) || [] 
        : []
    }
  }
];

