const rawOutput = $input.first().json.output; 

const cleanOutput = rawOutput.replace(/^```json\s*/i, "").replace(/^```\s*/i, "").replace(/\s*```$/, "");

let jsonData;
try {
    jsonData = JSON.parse(cleanOutput);
} catch (error) {
    jsonData = { error: "Gagal parsing JSON", raw: cleanOutput };
}

return { json: jsonData };

const data = $input.first().json;
const msg = data.message || "";

// keyword
const keywordMatch = msg.match(/Verify\w+Keyword/);
const keyword = keywordMatch ? keywordMatch[0] : "UNKNOWN";

// object repository
const repoMatch = msg.match(/Object Repository\/[^\r\n']+/);
const objectRepo = repoMatch ? repoMatch[0] : "UNKNOWN";

// xpath
const xpathMatch = msg.match(/By\.xpath:\s*(.+?)'/);
const xpath = xpathMatch ? xpathMatch[1] : "UNKNOWN";

// fingerprint
const fingerprint =
`${data.caseId}|${keyword}|${objectRepo}|${xpath}`;

return [{
  json: {
    ...data,
    fingerprint
  }
}];

const targetFingerprint = $('Generate Fingerprint').first().json.fingerprint;
const existing = $input.all();
const match = existing.find(item => item.json.Fingerprint === targetFingerprint);

if (match) {
  // Duplicate found - output to branch 0
  return [{
    json: {
      isDuplicate: true,
      fingerprint: targetFingerprint,
      existingRow: match.json.Row || ''
    }
  }];
} else {
  // New - output to branch 1
  return [{
    json: {
      isDuplicate: false,
      fingerprint: targetFingerprint
    }
  }];
}

const parseInput = $('Parse Input').first().json;
const aiOutput = $('Parse Output AI').first().json;
const caseId = parseInput.caseId || "Unknown";
const msg = parseInput.message || "";
const keywordMatch = msg.match(/Verify\w+Keyword/);
const keyword = keywordMatch ? keywordMatch[0] : "UNKNOWN";
const repoMatch = msg.match(/Object Repository\/[^\r\n']+/);
const objectRepo = repoMatch ? repoMatch[0] : "UNKNOWN";
const xpathMatch = msg.match(/By\.xpath:\s*(.+?)'/);
const xpath = xpathMatch ? xpathMatch[1] : "UNKNOWN";
const fingerprint = caseId + '|' + keyword + '|' + objectRepo + '|' + xpath;
const steps = (aiOutput.description?.steps_to_reproduce || []).join('\n');
const row = [
  new Date().toISOString().replace('T', ' ').substring(0, 19),
  caseId,
  aiOutput.ticket_title?.feature || "",
  aiOutput.ticket_title?.sub_section || "",
  aiOutput.ticket_title?.issue_title || "",
  aiOutput.priority || "",
  aiOutput.severity || "",
  steps,
  aiOutput.description?.expected_result || "",
  aiOutput.description?.actual_result || "",
  fingerprint,
  "New",
  "",
  parseInput.url || "",
  msg
];
return [{json: {row: row, fingerprint: fingerprint}}];

